import{_ as t,o as e,c as a,ae as n}from"./chunks/framework.Dzr56EFm.js";const c=JSON.parse('{"title":"设计趋势 - 2026-03-19","description":"","frontmatter":{"date":"2026-03-19T00:00:00.000Z","category":"UX Trend"},"headers":[],"relativePath":"daily/2026-03-19-uxtrend.md","filePath":"daily/2026-03-19-uxtrend.md"}'),o={name:"daily/2026-03-19-uxtrend.md"};function s(i,r,g,p,h,d){return e(),a("div",null,[...r[0]||(r[0]=[n('<h1 id="设计趋势-2026-03-19" tabindex="-1">设计趋势 - 2026-03-19 <a class="header-anchor" href="#设计趋势-2026-03-19" aria-label="Permalink to &quot;设计趋势 - 2026-03-19&quot;">​</a></h1><blockquote><p>AI交互方式、Prompt UX、Agent UX、Workflow</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日设计趋势聚焦于人工智能代理的用户体验。主要动态包括：1) 代理性用户体验设计指南强调理解用户目标和偏好的重要性；2) AI交互模式的探索，旨在让用户轻松识别并互动AI功能；3) 从人为中心的设计转变为包含智能代理的设计；4) ChatGPT的UI/UX重新设计案例研究，提升用户体验；5) 设计AI体验时需考虑的指导原则。最值得关注的是AI交互模式的探索和设计AI体验的指导原则。</p><hr><h3 id="_1-为代理性用户体验设计指南" tabindex="-1">1. 为代理性用户体验设计指南 <a class="header-anchor" href="#_1-为代理性用户体验设计指南" aria-label="Permalink to &quot;1. 为代理性用户体验设计指南&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/ai-ux-designers/era-of-agentive-ux-not-agentic-64dd765a0372" target="_blank" rel="noreferrer">Designing for Agentive UX — A Guide | by Kshitij Agrawal</a></p><p><strong>一句话摘要</strong>: 理解用户目标和偏好是设计代理的关键</p><p><strong>能解决什么问题</strong>: 解决如何使代理型产品理解并满足用户需求的问题</p><p><strong>产品应用</strong>: 可应用于智能助手和自动化服务，通过分析用户行为优化体验</p><p><strong>示例场景</strong>: 智能助手根据用户偏好推荐个性化内容</p><hr><h3 id="_2-ai交互模式-让用户识别并互动ai驱动功能" tabindex="-1">2. AI交互模式：让用户识别并互动AI驱动功能 <a class="header-anchor" href="#_2-ai交互模式-让用户识别并互动ai驱动功能" aria-label="Permalink to &quot;2. AI交互模式：让用户识别并互动AI驱动功能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@flik185/ai-interaction-patterns-giving-users-ways-to-recognize-and-interact-with-ai-driven-features-22055a91206b" target="_blank" rel="noreferrer">AI Interaction Patterns: Giving Users Ways to Recognize ...</a></p><p><strong>一句话摘要</strong>: 探索如何通过新的交互模式让用户轻松识别和与AI互动。</p><p><strong>能解决什么问题</strong>: 如何让用户与AI建立信任并充分利用AI功能。</p><p><strong>产品应用</strong>: 适用于AI工具，如聊天机器人、分析仪表板和个性化推荐。</p><p><strong>示例场景</strong>: 聊天机器人中明确告知用户正在与AI对话。</p><hr><h3 id="_3-ai-ux-人工智能代理的体验设计" tabindex="-1">3. AI/UX：人工智能代理的体验设计 <a class="header-anchor" href="#_3-ai-ux-人工智能代理的体验设计" aria-label="Permalink to &quot;3. AI/UX：人工智能代理的体验设计&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/i-ux/ai-ux-experience-design-of-ai-agents-12e1051fa065" target="_blank" rel="noreferrer">AI/UX: Experience Design of AI Agents | by Noman Siddiqui</a></p><p><strong>一句话摘要</strong>: 从以人为中心的设计转变为包含智能代理的设计。</p><p><strong>能解决什么问题</strong>: 如何为不需要传统UX元素的AI代理设计体验。</p><p><strong>产品应用</strong>: 可以应用到智能助手、聊天机器人等产品中，通过结构化数据和API提升用户体验。</p><p><strong>示例场景</strong>: AI代理自动安排会议并处理数据。</p><hr><h3 id="_4-重新构想chatgpt-ui-ux重新设计案例研究" tabindex="-1">4. 重新构想ChatGPT：UI/UX重新设计案例研究 <a class="header-anchor" href="#_4-重新构想chatgpt-ui-ux重新设计案例研究" aria-label="Permalink to &quot;4. 重新构想ChatGPT：UI/UX重新设计案例研究&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/reimagining-chatgpt-ui-ux-redesign-case-study-a9927c171a1b" target="_blank" rel="noreferrer">Reimagining ChatGPT: UI/UX Redesign Case Study</a></p><p><strong>一句话摘要</strong>: 通过UI/UX重新设计提升ChatGPT的用户体验</p><p><strong>能解决什么问题</strong>: ChatGPT的当前网页界面缺乏直观导航，难以生成和分享结果</p><p><strong>产品应用</strong>: 可应用于实际产品，通过改进界面和增加功能提高用户参与度和留存</p><p><strong>示例场景</strong>: 用户通过新界面轻松生成和分享ChatGPT的对话结果</p><hr><h3 id="_5-设计人工智能体验-指导原则" tabindex="-1">5. 设计人工智能体验：指导原则 <a class="header-anchor" href="#_5-设计人工智能体验-指导原则" aria-label="Permalink to &quot;5. 设计人工智能体验：指导原则&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/ai-and-service-design/designing-ai-experiences-p-3-guiding-principles-95b0c745973b" target="_blank" rel="noreferrer">Designing AI Experiences p.3: Guiding principles</a></p><p><strong>一句话摘要</strong>: 设计AI体验时应考虑可见性、上下文感知和多模态交互。</p><p><strong>能解决什么问题</strong>: 解决用户在零交互服务中的困惑和个性化体验需求。</p><p><strong>产品应用</strong>: 适用于自动化服务，通过检测用户环境提供定制化体验。</p><p><strong>示例场景</strong>: 在用户工作时，AI服务通过上下文感知避免打扰。</p><hr><h3 id="_6-ux设计师指南-如何有效提示" tabindex="-1">6. UX设计师指南：如何有效提示 <a class="header-anchor" href="#_6-ux设计师指南-如何有效提示" aria-label="Permalink to &quot;6. UX设计师指南：如何有效提示&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/a-ux-designer-guide-to-prompt-f045cd839489" target="_blank" rel="noreferrer">A UX designer guide to prompt</a></p><p><strong>一句话摘要</strong>: UX设计师通过有效提示，帮助AI模型理解用户请求。</p><p><strong>能解决什么问题</strong>: 解决人机交互中AI模型理解用户指令的问题。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过设计系统提示和用户界面提升体验。</p><p><strong>示例场景</strong>: 设计聊天机器人界面，使用提示芯片引导对话。</p><hr><h3 id="_7-7种关键的ai-ux模式实例" tabindex="-1">7. 7种关键的AI UX模式实例 <a class="header-anchor" href="#_7-7种关键的ai-ux模式实例" aria-label="Permalink to &quot;7. 7种关键的AI UX模式实例&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/bestfolios/building-trust-and-enhancing-interactions-7-essential-ai-ux-patterns-in-action-12e7604de435" target="_blank" rel="noreferrer">7 Essential AI UX Patterns in Action | by bestfolios.com</a></p><p><strong>一句话摘要</strong>: AI UX模式通过上下文提及和智能代码块等增强交互。</p><p><strong>能解决什么问题</strong>: 提升AI交互的实用性和开发效率。</p><p><strong>产品应用</strong>: 适用于AI界面设计，如代码助手和企业工具。</p><p><strong>示例场景</strong>: ChatGPT通过智能代码块提供代码操作。</p><hr><h3 id="_8-定义人工智能未来8大设计突破" tabindex="-1">8. 定义人工智能未来8大设计突破 <a class="header-anchor" href="#_8-定义人工智能未来8大设计突破" aria-label="Permalink to &quot;8. 定义人工智能未来8大设计突破&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/8-design-breakthroughs-defining-ais-future-21f7941ed160" target="_blank" rel="noreferrer">8 design breakthroughs defining AI&#39;s future</a></p><p><strong>一句话摘要</strong>: 界面设计者在探索人工智能交互的新领域。</p><p><strong>能解决什么问题</strong>: 缺乏成熟的模式和经验，难以设计有效的人工智能交互界面。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过实验发现有效的交互模式。</p><p><strong>示例场景</strong>: 智能助手通过学习用户习惯提供个性化服务。</p><hr><h3 id="_9-chatgpt更新-彻底变革的钩子" tabindex="-1">9. ChatGPT更新：彻底变革的钩子 <a class="header-anchor" href="#_9-chatgpt更新-彻底变革的钩子" aria-label="Permalink to &quot;9. ChatGPT更新：彻底变革的钩子&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@gentechimports/updates-for-chatgpt-6ddfabf1a424" target="_blank" rel="noreferrer">Updates for ChatGPT. The Hook That Changes Everything</a></p><p><strong>一句话摘要</strong>: ChatGPT正从聊天机器人转变为AI操作系统</p><p><strong>能解决什么问题</strong>: 解决未来十年人机交互方式的定义问题</p><p><strong>产品应用</strong>: 可应用于智能助手、客服等领域，提升交互效率</p><p><strong>示例场景</strong>: 智能客服通过ChatGPT提供实时语音服务</p><hr><h3 id="_10-5个ai原则-实现更有意图的设计" tabindex="-1">10. 5个AI原则，实现更有意图的设计 <a class="header-anchor" href="#_10-5个ai原则-实现更有意图的设计" aria-label="Permalink to &quot;10. 5个AI原则，实现更有意图的设计&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@faypiyth/5-ai-principles-for-more-intentional-design-491d2d143293" target="_blank" rel="noreferrer">5 AI Principles for More Intentional Design</a></p><p><strong>一句话摘要</strong>: AI辅助设计应保持个性、真实性和透明度。</p><p><strong>能解决什么问题</strong>: 如何在使用AI工具时保持设计的个性化和真实性。</p><p><strong>产品应用</strong>: 适用于产品设计，通过个性化设计和用户互动提升用户体验。</p><p><strong>示例场景</strong>: 电商网站使用AI生成个性化推荐和用户交互。</p><hr>',75)])])}const u=t(o,[["render",s]]);export{c as __pageData,u as default};
